 3. Agent&Trace梳理完了训练的整体流程，我发现 Agent 如何生成一条 Trace 是我们最需要了解的，其他部分的代码就是之前 LLM RL 的内容。 python import json import re from typing import Any, Optional import torch from openai import OpenAI from transformers import AutoModelForCausalLM, AutoTokenizer SYSTEM_PROMPT_TEMPLATE = """You are a helpful assistant that can use tools to answer questions. Available tools: {tools_description} STRICT RULES - you MUST follow these: 1. You cannot fabricate answers for unknown knowledge points; 2. Instead, use tools to retrieve relevant information. To use a tool, respond in this EXACT format: <think>[your reasoning, explain WHY you need to call the tool]</think> <tool><tool_name>[tool_name]</tool_name><arguments>{{"param1": "value1"}}</arguments></tool> After receiving the tool result, THEN respond: <think>[your reasoning based on the tool result]</think> <answer>[your answer]</answer> Only call one tool at a time.""" class Tool: def __init__(self, name: str, func: callable, desc: Optional[str] = None) -> None: self.name = name self.desc = desc self.func = func def __call__(self, *args: Any, **kwargs: Any) -> Any: return self.func(*args, **kwargs) def to_schema(self) -> dict: import inspect sig = inspect.signature(self.func) params = {} for param_name, param in sig.parameters.items(): annotation = param.annotation if annotation is int: type_str = "integer" elif annotation is float: type_str = "number" elif annotation is bool: type_str = "boolean" else: type_str = "string" params[param_name] = {"type": type_str} return { "name": self.name, "description": self.desc, "parameters": { "type": "object", "properties": params, "required": list(params.keys()), }, } def to_tool(name: Optional[str] = None, desc: Optional[str] = None): def decorator(func): tool_name = name or func.__name__ return Tool(tool_name, func, desc) return decorator class Agent: def __init__( self, max_steps: int, tools: list[Tool] = [], model_id: Optional[str] = None, api_key: Optional[str] = None, base_url: Optional[str] = None, test: bool = False, ) -> None: self.max_steps = max_steps self.model_id = model_id self.test = test self.temperature = 0.9 self.max_new_tokens = 1024 self.tools = {tool.name: tool for tool in tools} tools_desc = "

".join( f"Tool: {t.name}
Description: {t.desc}
Parameters: {json.dumps(t.to_schema()['parameters']['properties'])}" for t in tools ) self.system_prompt = SYSTEM_PROMPT_TEMPLATE.format(tools_description=tools_desc) if test: self.client = OpenAI(api_key=api_key, base_url=base_url) self.generate = self.generate_openai else: self.model = AutoModelForCausalLM.from_pretrained(model_id) self.tokenizer = AutoTokenizer.from_pretrained(model_id) self.generate = self.generate_transformers def generate_transformers(self, messages: list[dict]) -> str: prompt_text = self.tokenizer.apply_chat_template( messages, add_generation_prompt=True, tokenize=False, ) inputs = self.tokenizer(prompt_text, return_tensors="pt") if torch.cuda.is_available(): inputs = {k: v.cuda() for k, v in inputs.items()} with torch.inference_mode(): output_ids = self.model.generate( **inputs, max_new_tokens=self.max_new_tokens, do_sample=True, temperature=self.temperature, pad_token_id=self.tokenizer.pad_token_id, ) new_ids = output_ids[0][inputs["input_ids"].shape[1] :] return self.tokenizer.decode(new_ids, skip_special_tokens=True) def generate_openai(self, messages: list[dict]) -> str: response = self.client.chat.completions.create( model=self.model_id, messages=messages, max_tokens=self.max_new_tokens, temperature=self.temperature, ) return response.choices[0].message.content def parse_output(self, text: str) -> dict: result = { "thought": None, "tool_name": None, "arguments": None, "final_answer": None, "raw": text, } # 解析 <think> think_match = re.search(r"<think>(.*?)</think>", text, re.DOTALL) if think_match: result["thought"] = think_match.group(1).strip() # 解析 <answer>，优先返回 answer_match = re.search( r"<answer>(.*?)</answer>", text, re.DOTALL | re.IGNORECASE ) if answer_match:

